/* Views/Reviews/Product.cshtml */
@model ProductReviewsMvc.Controllers.ProductReviewsViewModel

@{
    ViewBag.Title = Model.ProductName + " Reviews";
}

<h2>@Model.ProductName Reviews</h2>

<div class="reviews">
    @if (Model.Reviews != null && Model.Reviews.Any())
    {
        foreach (var review in Model.Reviews)
        {
            <article class="review">
                <header>
                    <strong>@Html.Encode(review.UserName)</strong>
                    <span> - @review.Rating/5</span>
                    <span> - @review.CreatedAtUtc.ToLocalTime().ToString("g")</span>
                </header>
                <div class="review-body">
                    @review.FormattedContent
                </div>
            </article>
        }
    }
    else
    {
        <p>No reviews yet.</p>
    }
</div>

<hr />

<h3>Add a Review</h3>

@using (Html.BeginForm("Add", "Reviews", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    @Html.Hidden("ProductId", Model.ProductId)

    <div>
        <label for="UserName">Name</label>
        <input type="text" id="UserName" name="UserName" maxlength="100" required />
    </div>

    <div>
        <label for="Rating">Rating</label>
        <select id="Rating" name="Rating" required>
            <option value="">Select</option>
            <option value="1">1</option>
            <option value="2">2</option>
            <option value="3">3</option>
            <option value="4">4</option>
            <option value="5">5</option>
        </select>
    </div>

    <div>
        <label for="Content">Review</label>
        <textarea id="Content" name="Content" rows="6" maxlength="4000" required></textarea>
        <p>Formatting supported: **bold** and *italic*</p>
    </div>

    <button type="submit">Submit Review</button>
}